func HashDirectory(dir string, ignoreFns ...IgnoreFn) (string, error) {
	md5Hash := md5.New()

	walkErr := filepath.Walk(dir, func(path string, fi os.FileInfo, err error) error {
		if err != nil {
			return errors.Wrap(err, path)
		}

		for _, ignoreFn := range ignoreFns {
			ignore, err := ignoreFn(path, fi)
			if err != nil {
				return errors.Wrap(err, path)
			}
			if ignore {
				if fi.IsDir() {
					return filepath.SkipDir
				}
				return nil
			}
		}
		if fi.IsDir() {
			return nil
		}
		f, err := os.Open(path)
		if err != nil {
			return errors.Wrap(err, path)
		}
		defer f.Close()

		if _, err := io.Copy(md5Hash, f); err != nil {
			return errors.Wrap(err, path)
		}

		io.WriteString(md5Hash, path)
		return nil
	})

	if walkErr != nil {
		return "", walkErr
	}

	return hex.EncodeToString(md5Hash.Sum(nil)), nil
}

func HashFile(path string, paths ...string) (string, error) {
	md5Hash := md5.New()

	allPaths := append(paths, path)
	for _, path := range allPaths {
		f, err := Open(path)
		if err != nil {
			return "", err
		}

		// Skip directories
		fileInfo, err := f.Stat()
		if err != nil {
			f.Close()
			return "", errors.WithStack(err)
		}
		if fileInfo.IsDir() {
			f.Close()
			continue
		}

		if _, err := io.Copy(md5Hash, f); err != nil {
			f.Close()
			return "", errors.Wrap(err, path)
		}

		io.WriteString(md5Hash, path)
		f.Close()
	}

	return hex.EncodeToString(md5Hash.Sum(nil)), nil
}

func (c *Client) HashS3Dir(bucket string, prefix string, maxResults *int64, startAfter *string) (string, error) {
	md5Hash := md5.New()

	err := c.S3BatchIterator(bucket, prefix, true, maxResults, startAfter, func(objects []*s3.Object) (bool, error) {
		var subErr error
		for _, object := range objects {
			io.WriteString(md5Hash, *object.ETag)
		}
		return true, subErr
	})

	if err != nil {
		return "", err
	}

	return hex.EncodeToString(md5Hash.Sum(nil)), nil
}

func makeOperatorRequest(operatorConfig OperatorConfig, request *http.Request) ([]byte, error) {
	if operatorConfig.Telemetry {
		values := request.URL.Query()
		values.Set("clientID", operatorConfig.ClientID)
		request.URL.RawQuery = values.Encode()
	}

	request.Header.Set("CortexAPIVersion", consts.CortexVersion)
	awsClient, err := aws.New()
	if err != nil {
		return nil, err
	}

	authHeader, err := awsClient.IdentityRequestAsHeader()
	if err != nil {
		return nil, err
	}
	request.Header.Set(consts.AuthHeader, authHeader)

	timeout := 600 * time.Second
	if request.URL.Path == "/info" {
		timeout = 10 * time.Second
	}

	client := &http.Client{
		Timeout: timeout,
		Transport: &http.Transport{
			TLSClientConfig: &tls.Config{InsecureSkipVerify: true},
		},
	}

	response, err := client.Do(request)
	if err != nil {
		return nil, ErrorFailedToConnectOperator(err, operatorConfig.EnvName, operatorConfig.OperatorEndpoint)
	}
	defer response.Body.Close()

	if response.StatusCode != 200 {
		bodyBytes, err := ioutil.ReadAll(response.Body)
		if err != nil {
			return nil, errors.Wrap(err, _errStrRead)
		}

		var output schema.ErrorResponse
		err = json.Unmarshal(bodyBytes, &output)
		if err != nil || output.Message == "" {
			return nil, ErrorOperatorResponseUnknown(string(bodyBytes), response.StatusCode)
		}

		return nil, errors.WithStack(&errors.Error{
			Kind:        output.Kind,
			Message:     output.Message,
			NoTelemetry: true,
		})
	}

	bodyBytes, err := ioutil.ReadAll(response.Body)
	if err != nil {
		return nil, errors.Wrap(err, _errStrRead)
	}
	return bodyBytes, nil
}

func streamLogs(operatorConfig OperatorConfig, path string, qParams ...map[string]string) error {
	interrupt := make(chan os.Signal, 1)
	signal.Notify(interrupt, os.Interrupt)

	req, err := operatorRequest(operatorConfig, "GET", path, nil, qParams...)
	if err != nil {
		return err
	}

	values := req.URL.Query()
	if operatorConfig.Telemetry {
		values.Set("clientID", operatorConfig.ClientID)
	}

	req.URL.RawQuery = values.Encode()
	wsURL := req.URL.String()
	wsURL = strings.Replace(wsURL, "http", "ws", 1)

	header := http.Header{}
	header.Set("CortexAPIVersion", consts.CortexVersion)
	awsClient, err := aws.New()
	if err != nil {
		return err
	}

	authHeader, err := awsClient.IdentityRequestAsHeader()
	if err != nil {
		return err
	}
	header.Set(consts.AuthHeader, authHeader)

	var dialer = websocket.Dialer{
		TLSClientConfig: &tls.Config{InsecureSkipVerify: true},
	}

	connection, response, err := dialer.Dial(wsURL, header)
	if err != nil && response == nil {
		return ErrorFailedToConnectOperator(err, operatorConfig.EnvName, strings.Replace(operatorConfig.OperatorEndpoint, "http", "ws", 1))
	}
	defer response.Body.Close()

	if err != nil {
		bodyBytes, err := ioutil.ReadAll(response.Body)
		if err != nil || bodyBytes == nil || string(bodyBytes) == "" {
			return ErrorFailedToConnectOperator(err, operatorConfig.EnvName, strings.Replace(operatorConfig.OperatorEndpoint, "http", "ws", 1))
		}
		var output schema.ErrorResponse
		err = json.Unmarshal(bodyBytes, &output)
		if err != nil || output.Message == "" {
			return ErrorOperatorStreamResponseUnknown(string(bodyBytes), response.StatusCode)
		}
		return errors.WithStack(&errors.Error{
			Kind:        output.Kind,
			Message:     output.Message,
			NoTelemetry: true,
		})
	}
	defer connection.Close()

	done := make(chan struct{})
	handleConnection(connection, done)
	closeConnection(connection, done, interrupt)
	return nil
}

func validateOperatorEndpoint(endpoint string) (string, error) {
	url, err := cliconfig.CortexEndpointValidator(endpoint)
	if err != nil {
		return "", err
	}

	parsedURL, err := urls.Parse(url)
	if err != nil {
		return "", err
	}

	url = parsedURL.String()

	req, err := http.NewRequest("GET", urls.Join(url, "/verifycortex"), nil)
	if err != nil {
		return "", errors.Wrap(err, "verifying operator endpoint", url)
	}

	client := http.Client{
		Transport: &http.Transport{
			TLSClientConfig: &tls.Config{InsecureSkipVerify: true},
		},
	}

	response, err := client.Do(req)
	if err != nil {
		return "", ErrorInvalidOperatorEndpoint(url)
	}
	defer response.Body.Close()

	if response.StatusCode != 200 {
		return "", ErrorInvalidOperatorEndpoint(url)
	}

	bodyBytes, err := ioutil.ReadAll(response.Body)
	if err != nil {
		return "", errors.Wrap(err, _errStrRead)
	}

	var verifyCortex schema.VerifyCortexResponse
	if err = json.Unmarshal(bodyBytes, &verifyCortex); err != nil {
		return "", errors.Wrap(err, endpoint, string(bodyBytes))
	}

	return url, nil
}

func MakeRequest(request *http.Request) (http.Header, []byte, error) {
	client := http.Client{
		Timeout: 5 * time.Second,
		Transport: &http.Transport{
			TLSClientConfig: &tls.Config{InsecureSkipVerify: true},
		},
	}

	response, err := client.Do(request)
	if err != nil {
		return nil, nil, errors.Wrap(err, errStrFailedToConnect(*request.URL))
	}
	defer response.Body.Close()

	if response.StatusCode != 200 {
		bodyBytes, err := ioutil.ReadAll(response.Body)
		if err != nil {
			return nil, nil, errors.Wrap(err, _errStrRead)
		}
		return nil, nil, ErrorResponseUnknown(string(bodyBytes), response.StatusCode)
	}

	bodyBytes, err := ioutil.ReadAll(response.Body)
	if err != nil {
		return nil, nil, errors.Wrap(err, _errStrRead)
	}
	return response.Header, bodyBytes, nil
}
